<?php
function card_preview($card){$type=$card['type'];if($type==='Image'&&!empty($card['file_path']))return '<img src="'.e($card['file_path']).'" alt="preview">';if($type==='PDF')return '<div class="preview-inner"><div style="font-size:58px">📄</div><div style="font-weight:800">'.e($card['original_filename']?:'PDF document').'</div><div class="muted">Open PDF from actions.</div></div>';if($type==='Link'&&!empty($card['link_url'])){$host=parse_url($card['link_url'],PHP_URL_HOST);$domain=$host?preg_replace('/^www\./','',$host):'link';$icon='https://www.google.com/s2/favicons?sz=128&domain_url='.rawurlencode($card['link_url']);return '<div class="preview-inner"><div class="small">Link preview</div><div style="display:flex;gap:12px;align-items:center"><img src="'.e($icon).'" style="width:48px;height:48px;border-radius:12px;background:#fff;padding:8px"><div><div style="font-weight:800;font-size:20px">'.e($card['title']).'</div><div class="muted">'.e($domain).'</div></div></div></div>';}if($type==='Note'){$text=trim($card['note_content']?:$card['description']?:'Quick note');return '<div class="preview-inner"><div class="small">Note</div><div style="font-size:16px;line-height:1.55;color:#dbe4ff">'.e(mb_strimwidth($text,0,220,'…')).'</div></div>';}return '<div class="preview-inner"><div style="font-size:58px">🗂️</div><div class="muted">Saved item</div></div>';}
function render_card($card,$owner=true){$search=strtolower(trim(($card['title']??'').' '.($card['description']??'').' '.($card['category']??'').' '.($card['tags']??'').' '.($card['link_url']??'').' '.($card['note_content']??'')));?>
<article class="panel card vault-item" data-search="<?= e($search) ?>" data-type="<?= e($card['type']) ?>" data-visibility="<?= e($card['visibility']) ?>"><div class="preview"><div class="file-badge"><?= e($card['type']) ?></div><div class="visibility"><?= e($card['visibility']) ?></div><?= card_preview($card) ?></div><div class="card-body"><h3 class="card-title"><?= e($card['title']) ?></h3><?php if(!empty($card['description'])): ?><div class="desc"><?= e($card['description']) ?></div><?php endif; ?><div class="meta"><?php if(!empty($card['category'])): ?><span class="tag">#<?= e($card['category']) ?></span><?php endif; ?><?php foreach(array_filter(array_map('trim',explode(',',$card['tags']??''))) as $tag): ?><span class="tag"><?= e($tag) ?></span><?php endforeach; ?></div><div class="card-footer"><div class="small"><?= date('d M Y',strtotime($card['created_at'])) ?></div><div class="card-actions"><?php if($card['type']==='Link'&&!empty($card['link_url'])): ?><a class="icon-btn" target="_blank" href="<?= e($card['link_url']) ?>">Open</a><?php endif; ?><?php if($card['type']==='PDF'&&!empty($card['file_path'])): ?><a class="icon-btn" target="_blank" href="<?= e($card['file_path']) ?>">Open PDF</a><?php endif; ?><?php if($owner): ?><a class="icon-btn" href="toggle.php?id=<?= (int)$card['id'] ?>"><?= $card['visibility']==='Public'?'Make Private':'Make Public' ?></a><a class="icon-btn" href="delete.php?id=<?= (int)$card['id'] ?>" onclick="return confirm('Delete this card?')">Delete</a><?php endif; ?></div></div></div></article><?php }
?>